// Navbar.js
import React, { useEffect, useState } from "react";
import { useNavigate, Link, useLocation } from "react-router-dom";

export default function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();
  const [activeSection, setActiveSection] = useState("accueil");

  const handleNavScroll = (hash) => {
    if (location.pathname !== "/") {
      navigate(`/#${hash}`);
    } else {
      const element = document.getElementById(hash);
      if (element) {
        element.scrollIntoView({ behavior: "smooth" });
      }
    }
  };

  useEffect(() => {
    const handleScroll = () => {
      const sections = ["accueil", "services", "equipe", "contact"];
      let current = "accueil";
      for (const id of sections) {
        const section = document.getElementById(id);
        if (section && window.scrollY >= section.offsetTop - 100) {
          current = id;
        }
      }
      setActiveSection(current);
    };

    if (location.pathname === "/") {
      window.addEventListener("scroll", handleScroll);
      return () => window.removeEventListener("scroll", handleScroll);
    }
  }, [location.pathname]);

  return (
    <nav className="sticky top-0 bg-navy shadow-md z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center justify-between">
        <div className="flex items-center space-x-3">
          <img src="/alforis_logo_precise_round.png" alt="Logo Alforis" className="h-10 w-10 rounded-full" />
          <span className="text-white font-title text-xl font-semibold">Alforis</span>
        </div>
        <div className="hidden md:flex space-x-8 text-sm font-medium">
          {[
            { id: "accueil", label: "Accueil" },
            { id: "services", label: "Services" },
            { id: "equipe", label: "Équipe" },
            { id: "contact", label: "Contact" },
          ].map(({ id, label }) => (
            <button
              key={id}
              onClick={() => handleNavScroll(id)}
              className={`transition hover:text-gold ${
                activeSection === id ? "text-gold" : "text-white"
              }`}
            >
              {label}
            </button>
          ))}
        </div>
        <Link
          to="/rendezvous"
          className="bg-gold text-navy px-4 py-2 rounded-md text-sm font-semibold hover:opacity-90 transition"
        >
          Prendre un RDV
        </Link>
      </div>
    </nav>
  );
}
